import { useState } from "react";
import { useNavigate } from "react-router-dom";
import axios from 'axios';
import './AjouterUtilisateur.css';

export default function Ajouter(){
    const [username,setUsername] = useState('');
    const [email,setEmail] = useState('');
    const [password,setPassword] = useState('');
    const [role,setRole] = useState('');
    const navigate = useNavigate();
    const token = localStorage.getItem("token");

    const addUser = async (e) => {
        e.preventDefault(); // Prevent default form submission
        const newUser = {
            username : username,
            email : email,
            password : password,
            role : role
        }
        const res = await axios.post('http://localhost:3001/add', newUser, {
          headers: { Authorization: `Bearer ${token}` }
        });
        navigate('/AfficherUtilisateurs');
    }

    return (
        <div className="add-user-container">
            <div className="add-user-card">
                <div className="card-header">
                    <h1>Ajouter un Utilisateur</h1>
                    <p>Remplissez les informations pour créer un nouveau compte utilisateur</p>
                </div>

                <form onSubmit={addUser} className="add-user-form">
                    <div className="form-group">
                        <label htmlFor="username">Nom d'utilisateur</label>
                        <input
                            type="text"
                            id="username"
                            value={username}
                            onChange={(e) => setUsername(e.target.value)}
                            placeholder="Entrez le nom d'utilisateur"
                            required
                        />
                    </div>

                    <div className="form-group">
                        <label htmlFor="email">Adresse Email</label>
                        <input
                            type="email"
                            id="email"
                            value={email}
                            onChange={(e) => setEmail(e.target.value)}
                            placeholder="Entrez l'adresse email"
                            required
                        />
                    </div>

                    <div className="form-group">
                        <label htmlFor="password">Mot de passe</label>
                        <input
                            type="password"
                            id="password"
                            value={password}
                            onChange={(e) => setPassword(e.target.value)}
                            placeholder="Entrez le mot de passe"
                            required
                        />
                    </div>

                    <div className="form-group">
                        <label htmlFor="role">Rôle</label>
                        <select
                            id="role"
                            value={role}
                            onChange={(e) => setRole(e.target.value)}
                            required
                        >
                            <option value="" disabled>Choisissez un rôle</option>
                            <option value="admin">Administrateur</option>
                            <option value="student">Étudiant</option>
                        </select>
                    </div>

                    <div className="form-actions">
                        <button type="button" onClick={() => navigate('/AfficherUtilisateurs')} className="cancel-btn">
                            Annuler
                        </button>
                        <button type="submit" className="submit-btn">
                            ➕ Ajouter l'utilisateur
                        </button>
                    </div>
                </form>
            </div>
        </div>
    )
}
